function normalize(value) {
  return String(value)
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toLowerCase();
}

function escapeRegExp(value) {
  return value.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
}

function findTokens(text, bookId) {
  const matches = [];
  const occupied = [];

  function overlaps(start, end) {
    return occupied.some(range => start < range.end && end > range.start);
  }

  const normalizedText = normalize(text);
  const shortBank = shortProperWordBank[bookId] || {};

  Object.entries(shortBank).forEach(([strong, words]) => {
    words.forEach(word => {
      const regex = new RegExp(`(^|[^\\p{L}\\p{N}_])(${escapeRegExp(word)})(?=[^\\p{L}\\p{N}_]|$)`, "gu");
      let match;
      while ((match = regex.exec(text))) {
        const start = match.index + match[1].length;
        const end = start + match[2].length;
        if (overlaps(start, end)) continue;
        const visible = text.slice(start, end);
        occupied.push({ start, end });
        matches.push({ start, word: visible, strong });
      }
    });
  });

  const bank = { ...wordBank, ...(bookWordBank[bookId] || {}) };

  Object.entries(bank).forEach(([strong, words]) => {
    words
      .slice()
      .sort((left, right) => right.length - left.length)
      .forEach(word => {
        const normalizedWord = normalize(word);
        if (normalizedWord.length < 3) return;
        const regex = new RegExp(`(^|[^\\p{L}\\p{N}_])(${escapeRegExp(normalizedWord)})(?=[^\\p{L}\\p{N}_]|$)`, "giu");
        let match;
        while ((match = regex.exec(normalizedText))) {
          const start = match.index + match[1].length;
          const end = start + match[2].length;
          if (overlaps(start, end)) continue;
          const visible = text.slice(start, end);
          occupied.push({ start, end });
          matches.push({ start, word: visible, strong });
        }
      });
  });

  return matches
    .sort((left, right) => left.start - right.start || left.strong.localeCompare(right.strong))
    .map(({ word, strong }) => ({ word, strong }));
}

function readBook(file) {
  const raw = fs.readFileSync(file, "utf8");
  return JSON.parse(raw.replace(/^globalThis\.appData\.books\.push\(/, "").replace(/\);\s*$/, ""));
}

function writeBook(file, book) {
  fs.writeFileSync(file, `globalThis.appData.books.push(${JSON.stringify(book, null, 2)});\n`);
}

let markedWords = 0;
for (const id of otIds) {
  const file = path.join(booksDir, `${id}.js`);
  const book = readBook(file);
  for (const chapter of book.chapters) {
    for (const verse of chapter.verses) {
      verse.tokens = findTokens(verse.text, id);
      if (id === "exodus" && chapter.number === 2) {
        verse.tokens = verse.tokens.map(token => (
          token.strong === "H727" && normalize(token.word) === "arca"
            ? { ...token, strong: "H8392" }
            : token
        ));
      }
      if (id === "psalms") {
        verse.tokens = verse.tokens.map(token => {
          const normalizedWord = normalize(token.word);
          if (token.strong === "H1984" && ["louvor", "louvores"].includes(normalizedWord)) {
            return { ...token, strong: "H8416" };
          }
          if (token.strong === "H4733" && ["refugio", "abrigo"].includes(normalizedWord)) {
            return { ...token, strong: "H4268" };
          }
          return token;
        });
      }
      if (id === "proverbs") {
        verse.tokens = verse.tokens.map(token => {
          const normalizedWord = normalize(token.word);
          if (["H6666", "H4941"].includes(token.strong) && ["justo", "justos", "justa", "justas"].includes(normalizedWord)) {
            return { ...token, strong: "H6662" };
          }
          if (token.strong === "H998" && ["entendimento", "inteligencia"].includes(normalizedWord)) {
            return { ...token, strong: "H8394" };
          }
          if (token.strong === "H6310" && ["labio", "labios"].includes(normalizedWord)) {
            return { ...token, strong: "H8193" };
          }
          if (token.strong === "H4809" && ["contenda", "contendas"].includes(normalizedWord)) {
            return { ...token, strong: "H4066" };
          }
          return token;
        });
      }
      if (id === "song") {
        verse.tokens = verse.tokens.map(token => {
          const normalizedWord = normalize(token.word);
          if (token.strong === "H802" && ["esposa"].includes(normalizedWord)) {
            return { ...token, strong: "H3618" };
          }
          if (token.strong === "H2896" && ["formosa", "formoso", "bela", "belo"].includes(normalizedWord)) {
            return { ...token, strong: "H3303" };
          }
          return token;
        });
      }
      if (id === "isaiah") {
        verse.tokens = verse.tokens.map(token => {
          const normalizedWord = normalize(token.word);
          if (token.strong === "H6944" && ["santo", "santos", "santa", "santas"].includes(normalizedWord)) {
            return { ...token, strong: "H6918" };
          }
          if (token.strong === "H5387" && ["principe", "principes"].includes(normalizedWord)) {
            return { ...token, strong: "H8269" };
          }
          if (token.strong === "H6098" && ["conselheiro", "conselheiros"].includes(normalizedWord)) {
            return { ...token, strong: "H3289" };
          }
          if (token.strong === "H5797" && ["maravilhoso", "maravilha", "maravilhas"].includes(normalizedWord)) {
            return { ...token, strong: "H6382" };
          }
          return token;
        });
      }
      if (id === "daniel") {
        verse.tokens = verse.tokens.map(token => {
          const normalizedWord = normalize(token.word);
          if (token.strong === "H6944" && ["santo", "santos"].includes(normalizedWord)) {
            return { ...token, strong: "H6922" };
          }
          if (token.strong === "H4467" && ["reino", "reinos"].includes(normalizedWord)) {
            return { ...token, strong: "H4437" };
          }
          if (token.strong === "H5387" && ["principe", "principes"].includes(normalizedWord)) {
            return { ...token, strong: "H8269" };
          }
          if (token.strong === "H8163" && ["bode"].includes(normalizedWord)) {
            return { ...token, strong: "H6842" };
          }
          return token;
        });
      }
      markedWords += verse.tokens.length;
    }
  }
  writeBook(file, book);
}

const lexiconPayload = Object.fromEntries(Object.entries(hebrewLexicon).map(([strong, values]) => ([
  strong,
  {
    lemma: values[0],
    original: values[1],
    translit: values[2],
    grammar: values[3],
    gloss: values[4],
    exegetic: values[5],
    culture: values[6],
    parallels: values[7]
  }
])));

let lexicon = fs.readFileSync(lexiconFile, "utf8");
lexicon = lexicon.replace(/\n\/\/ BEGIN HEBREW STRONG LAYER[\s\S]*?\/\/ END HEBREW STRONG LAYER\n?/u, "\n");
lexicon += `\n// BEGIN HEBREW STRONG LAYER\nObject.assign(globalThis.appData.lexicon, ${JSON.stringify(lexiconPayload, null, 2)});\n// END HEBREW STRONG LAYER\n`;
fs.writeFileSync(lexiconFile, lexicon);

